import React from "react";

const TravelStay = () => (
  <section id="travel" className="card">
    <h3>Travel & Stay</h3>
    <p>
      For our beloved guests traveling from near and far, we have arranged comfortable
      accommodations close to the venue. Please reach out to us for details on hotels,
      transport, and local guidance.
    </p>
  </section>
);

export default TravelStay;
